const RATE_LIMIT_WINDOW = 60000;
const MAX_REQUESTS_PER_WINDOW = 10;

const ALLOWED_EMAIL_DOMAINS = ['gmail.com', 'yahoo.com', 'outlook.com', 'company.com'];
const MAX_EMAIL_LENGTH = 254;
const MAX_AMOUNT = 1000000;
const MIN_AMOUNT = 50;

function validateEmail(email) {
  if (!email || typeof email !== 'string' || email.length > MAX_EMAIL_LENGTH) {
    return false;
  }
  
  const emailRegex = /^[a-zA-Z0-9.!#$%&'*+\/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*$/;
  
  if (!emailRegex.test(email)) {
    return false;
  }
  
  const domain = email.split('@')[1];
  return ALLOWED_EMAIL_DOMAINS.includes(domain);
}

function validateAmount(amount) {
  if (typeof amount !== 'number' || isNaN(amount)) {
    return false;
  }
  
  return amount >= MIN_AMOUNT && amount <= MAX_AMOUNT && Number.isInteger(amount);
}

function validateCurrency(currency) {
  const allowedCurrencies = ['usd', 'eur', 'gbp'];
  return typeof currency === 'string' && allowedCurrencies.includes(currency.toLowerCase());
}

function sanitizeString(str, maxLength = 500) {
  if (typeof str !== 'string') {
    return '';
  }
  
  return str.slice(0, maxLength).replace(/[<>\"'&]/g, '');
}

async function checkRateLimit(request, env) {
  const ip = request.headers.get('CF-Connecting-IP') || 'unknown';
  const key = `ratelimit:${ip}`;
  
  const current = await env.RATE_LIMIT.get(key);
  const now = Date.now();
  
  if (current) {
    const data = JSON.parse(current);
    
    if (now - data.timestamp < RATE_LIMIT_WINDOW) {
      if (data.count >= MAX_REQUESTS_PER_WINDOW) {
        return false;
      }
      
      data.count += 1;
      await env.RATE_LIMIT.put(key, JSON.stringify(data), {
        expirationTtl: Math.ceil(RATE_LIMIT_WINDOW / 1000)
      });
    } else {
      await env.RATE_LIMIT.put(key, JSON.stringify({ count: 1, timestamp: now }), {
        expirationTtl: Math.ceil(RATE_LIMIT_WINDOW / 1000)
      });
    }
  } else {
    await env.RATE_LIMIT.put(key, JSON.stringify({ count: 1, timestamp: now }), {
      expirationTtl: Math.ceil(RATE_LIMIT_WINDOW / 1000)
    });
  }
  
  return true;
}

function validateOrigin(request, env) {
  const origin = request.headers.get('Origin');
  const allowedOrigins = env.ALLOWED_ORIGINS ? env.ALLOWED_ORIGINS.split(',') : [];
  
  if (!origin || !allowedOrigins.includes(origin)) {
    return false;
  }
  
  return true;
}

function validateApiKey(request, env) {
  const apiKey = request.headers.get('X-API-Key');
  
  if (!apiKey || typeof apiKey !== 'string') {
    return false;
  }
  
  return apiKey === env.API_KEY;
}

async function sendEmail(env, emailData) {
  const { to, subject, content } = emailData;
  
  if (!validateEmail(to)) {
    throw new Error('Invalid email address');
  }
  
  const sanitizedSubject = sanitizeString(subject, 200);
  const sanitizedContent = sanitizeString(content, 5000);
  
  if (!sanitizedSubject || !sanitizedContent) {
    throw new Error('Invalid email content');
  }
  
  const response = await fetch('https://api.sendgrid.com/v3/mail/send', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${env.SENDGRID_API_KEY}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      personalizations: [{
        to: [{ email: to }]
      }],
      from: { email: env.FROM_EMAIL },
      subject: sanitizedSubject,
      content: [{
        type: 'text/plain',
        value: sanitizedContent
      }]
    })
  });
  
  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`SendGrid API error: ${response.status}`);
  }
  
  return { success: true, message: 'Email sent successfully' };
}

async function createPaymentIntent(env, paymentData) {
  const { amount, currency, description } = paymentData;
  
  if (!validateAmount(amount)) {
    throw new Error('Invalid payment amount');
  }
  
  if (!validateCurrency(currency)) {
    throw new Error('Invalid currency');
  }
  
  const sanitizedDescription = sanitizeString(description, 500);
  
  const params = new URLSearchParams({
    amount: amount.toString(),
    currency: currency.toLowerCase(),
    description: sanitizedDescription || 'Payment'
  });
  
  const response = await fetch('https://api.stripe.com/v1/payment_intents', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${env.STRIPE_SECRET_KEY}`,
      'Content-Type': 'application/x-www-form-urlencoded'
    },
    body: params.toString()
  });
  
  if (!response.ok) {
    const errorData = await response.json();
    throw new Error(`Stripe API error: ${response.status}`);
  }
  
  const data = await response.json();
  
  return {
    success: true,
    paymentIntentId: data.id,
    clientSecret: data.client_secret,
    amount: data.amount,
    currency: data.currency
  };
}

async function handleRequest(request, env) {
  if (request.method === 'OPTIONS') {
    return new Response(null, {
      status: 204,
      headers: {
        'Access-Control-Allow-Origin': env.ALLOWED_ORIGINS || '*',
        'Access-Control-Allow-Methods': 'POST, OPTIONS',
        'Access-Control-Allow-Headers': 'Content-Type, X-API-Key',
        'Access-Control-Max-Age': '86400'
      }
    });
  }
  
  if (request.method !== 'POST') {
    return new Response(JSON.stringify({ error: 'Method not allowed' }), {
      status: 405,
      headers: { 'Content-Type': 'application/json' }
    });
  }
  
  if (!validateOrigin(request, env)) {
    return new Response(JSON.stringify({ error: 'Invalid origin' }), {
      status: 403,
      headers: { 'Content-Type': 'application/json' }
    });
  }
  
  if (!validateApiKey(request, env)) {
    return new Response(JSON.stringify({ error: 'Unauthorized' }), {
      status: 401,
      headers: { 'Content-Type': 'application/json' }
    });
  }
  
  const rateLimitOk = await checkRateLimit(request, env);
  if (!rateLimitOk) {
    return new Response(JSON.stringify({ error: 'Rate limit exceeded' }), {
      status: 429,
      headers: { 'Content-Type': 'application/json' }
    });
  }
  
  let body;
  try {
    const text = await request.text();
    if (text.length > 10000) {
      throw new Error('Request body too large');
    }
    body = JSON.parse(text);
  } catch (error) {
    return new Response(JSON.stringify({ error: 'Invalid JSON' }), {
      status: 400,
      headers: { 'Content-Type': 'application/json' }
    });
  }
  
  const { action } = body;
  
  if (!action || typeof action !== 'string') {
    return new Response(JSON.stringify({ error: 'Invalid action' }), {
      status: 400,
      headers: { 'Content-Type': 'application/json' }
    });
  }
  
  try {
    let result;
    
    if (action === 'send_email') {
      const { to, subject, content } = body;
      result = await sendEmail(env, { to, subject, content });
    } else if (action === 'create_payment') {
      const { amount, currency, description } = body;
      result = await createPaymentIntent(env, { amount, currency, description });
    } else {
      return new Response(JSON.stringify({ error: 'Unknown action' }), {
        status: 400,
        headers: { 'Content-Type': 'application/json' }
      });
    }
    
    return new Response(JSON.stringify(result), {
      status: 200,
      headers: {
        'Content-Type': 'application/json',
        'Access-Control-Allow-Origin': env.ALLOWED_ORIGINS || '*'
      }
    });
  } catch (error) {
    return new Response(JSON.stringify({ error: 'Internal server error' }), {
      status: 500,
      headers: { 'Content-Type': 'application/json' }
    });
  }
}

export default {
  async fetch(request, env, ctx) {
    try {
      return await handleRequest(request, env);
    } catch (error) {
      return new Response(JSON.stringify({ error: 'Internal server error' }), {
        status: 500,
        headers: { 'Content-Type': 'application/json' }
      });
    }
  }
};